```solidity
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract TeamVesting is ReentrancyGuard {
    enum State { Initialized, InvestorsAdded, TokensReleased }
    State public state;

    address public owner;
    uint256 public initialTimestamp;
    uint256 public totalAllocatedAmount;
    mapping(address => Investor) public investors;

    struct Investor {
        uint256 allocation;
        uint256 withdrawnAmount;
        uint256 vestingStart;
        uint256 vestingDuration;
    }

    event InvestorsAdded(address[] investors);
    event TokensReleased();
    event TokensWithdrawn(address indexed investor, uint256 amount);
    event TokenRecovery(address indexed token, address indexed to, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    constructor() {
        owner = msg.sender;
        state = State.Initialized;
    }

    function initialize(uint256 _initialTimestamp) external onlyOwner {
        require(state == State.Initialized, "Already initialized");
        initialTimestamp = _initialTimestamp;
        state = State.InvestorsAdded;
    }

    function addInvestors(address[] calldata _investors, uint256[] calldata _allocations, uint256[] calldata _vestingStarts, uint256[] calldata _vestingDurations) external onlyOwner {
        require(state == State.InvestorsAdded, "Invalid state");
        require(_investors.length == _allocations.length && _investors.length == _vestingStarts.length && _investors.length == _vestingDurations.length, "Mismatched arrays");

        for (uint256 i = 0; i < _investors.length; i++) {
            require(_investors[i] != address(0), "Invalid investor address");
            require(_allocations[i] > 0, "Allocation must be positive");
            require(_vestingStarts[i] > block.timestamp, "Vesting start time must be in the future");
            require(_vestingDurations[i] > 0, "Vesting duration must be positive");

            investors[_investors[i]] = Investor({
                allocation: _allocations[i],
                withdrawnAmount: 0,
                vestingStart: _vestingStarts[i],
                vestingDuration: _vestingDurations[i]
            });
            totalAllocatedAmount += _allocations[i];
        }

        emit InvestorsAdded(_investors);
    }

    function releaseTokens() external onlyOwner {
        require(state == State.InvestorsAdded, "Invalid state");
        state = State.TokensReleased;
        emit TokensReleased();
    }

    function withdrawTokens() external nonReentrant {
        require(state == State.TokensReleased, "Tokens not released yet");
        address investor = msg.sender;
        Investor storage inv = investors[investor];

        require(block.timestamp >= inv.vestingStart, "Vesting period has not started");
        require(block.timestamp < inv.vestingStart + inv.vestingDuration, "Vesting period has ended");

        uint256 vestedAmount = calculateVestedAmount(inv);
        uint256 amountToWithdraw = vestedAmount - inv.withdrawnAmount;
        require(amountToWithdraw > 0, "No tokens to withdraw");

        // Transfer tokens before updating state
        transferTokens(investor, amountToWithdraw);
        inv.withdrawnAmount += amountToWithdraw;
        emit TokensWithdrawn(investor, amountToWithdraw);
    }

    function recoverTokens(address _token, address _to, uint256 _amount) external onlyOwner nonReentrant {
        require(IERC20(_token).balanceOf(address(this)) >= _amount, "Insufficient balance");
        IERC20(_token).transfer(_to, _amount);
        emit TokenRecovery(_token, _to, _amount);
    }

    function calculateVestedAmount(Investor storage investor) internal view returns (uint256) {
        uint256 vestedTime = block.timestamp - investor.vestingStart;
        uint256 vestedPercentage = vestedTime * 100 / investor.vestingDuration;
        uint256 vestedAmount = investor.allocation * vestedPercentage / 100;
        return vestedAmount - investor.withdrawnAmount;
    }

    function transferTokens(address _to, uint256 _amount) internal {
        // Implement token transfer logic here
        // For example, if using ERC20 tokens:
        // IERC20(tokenAddress).transfer(_to, _amount);
    }
}
